"use strict";(self.webpackChunkpos_doc=self.webpackChunkpos_doc||[]).push([[817],{8599(t,e,a){a.r(e),a.d(e,{_pageData:()=>r,default:()=>o});var n=a(641);const r=JSON.parse('{"path":"/woocommerce-pos/cash-drawer.html","title":"WooCommerce POS – Cash Drawer & Cashier Management","lang":"en-US","frontmatter":{},"git":{"contributors":[{"name":"harshit","username":"","email":"harshit.qa322@webkul.in","commits":2},{"name":"nikhilsharma.qa322","username":"","email":"nikhilsharma.qa322@webkul.in","commits":1},{"name":"himanshu","username":"","email":"himanshu.kumar731@webkul.in","commits":1}],"changelog":[{"hash":"e0aac8ca5df6032b25db34a7bd8d20e0c0b22a40","time":1770293899000,"email":"harshit.qa322@webkul.in","author":"harshit","message":"updated doc"},{"hash":"d40e6fdaa8b21bf16d0e572854cf43f79756c0c7","time":1768918927000,"email":"himanshu.kumar731@webkul.in","author":"himanshu","message":"Added: Update Code for POS doc"},{"hash":"2f4cbdd59dfa7fa9497eed97a7f9fbdd46880420","time":1768311937000,"email":"nikhilsharma.qa322@webkul.in","author":"nikhilsharma.qa322","message":"add the images"},{"hash":"0f78e3256fa0d58de79a9cbca0c15a253149691b","time":1767359090000,"email":"harshit.qa322@webkul.in","author":"harshit","message":"updated content file"}]},"filePathRelative":"woocommerce-pos/cash-drawer.md"}'),s={name:"cash-drawer.md"},o=(0,a(6262).A)(s,[["render",function(t,e,a,r,s,o){return(0,n.uX)(),(0,n.CE)("div",null,[...e[0]||(e[0]=[(0,n.Fv)('<h1 id="woocommerce-pos-–-cash-drawer-cashier-management" tabindex="-1"><a class="header-anchor" href="#woocommerce-pos-–-cash-drawer-cashier-management"><span>WooCommerce POS – Cash Drawer &amp; Cashier Management</span></a></h1><p>Efficient cash handling is a critical part of in-store retail operations. <strong>WooCommerce Point of Sale (POS)</strong> provides a structured and transparent cash drawer and cashier management system that helps administrators and POS agents track daily cash flow, manage drawer openings and closures, and maintain accurate financial records.</p><p>This blog covers <strong>cash drawer operations, drawer automation, and cashier management features</strong> available in WooCommerce POS.</p><hr><h2 id="opening-the-cash-drawer" tabindex="-1"><a class="header-anchor" href="#opening-the-cash-drawer"><span>Opening the Cash Drawer</span></a></h2><p>Once a POS agent logs in to the POS panel, they are required to enter the <strong>opening cash drawer amount</strong> for the day.</p><h3 id="how-opening-cash-drawer-works" tabindex="-1"><a class="header-anchor" href="#how-opening-cash-drawer-works"><span>How Opening Cash Drawer Works</span></a></h3><ul><li>A popup appears prompting the POS agent to enter the <strong>opening amount</strong></li><li>Example: The agent enters <strong>$1000</strong>, which represents the starting cash for the day</li><li>This popup can be <strong>enabled or disabled by the admin</strong> from the POS settings</li></ul><p>Recording the opening balance ensures transparency and accuracy in daily cash tracking.</p><hr><h2 id="cash-drawer-management" tabindex="-1"><a class="header-anchor" href="#cash-drawer-management"><span>Cash Drawer Management</span></a></h2><p>WooCommerce POS allows administrators to configure and manage cash drawers effectively.</p><h3 id="drawer-overview" tabindex="-1"><a class="header-anchor" href="#drawer-overview"><span>Drawer Overview</span></a></h3><ul><li>Admin can: <ul><li>Set up the cash drawer</li><li>Review the details of the <strong>last drawer on a daily basis</strong></li></ul></li><li>The <strong>Closing Drawer Details</strong> section displays: <ul><li>Closing balance for a selected day</li><li>Summary of sales and cash movements</li></ul></li></ul><p>This helps ensure that all sales are properly recorded and reconciled.</p><hr><h2 id="cashier-management-features" tabindex="-1"><a class="header-anchor" href="#cashier-management-features"><span>Cashier Management Features</span></a></h2><p>WooCommerce POS includes advanced cashier-level tools to help POS agents manage daily transactions efficiently.</p><hr><h2 id="close-counter" tabindex="-1"><a class="header-anchor" href="#close-counter"><span>Close Counter</span></a></h2><p><img src="/pos-for-woocommerce/images/woocommerce-pos/closecounter.webp" alt="ManageoutletAndPosUser"></p><p>At the end of the shift, cashiers use the <strong>Close Counter</strong> screen to reconcile the drawer. Below is the breakdown of the closing fields:</p><table><thead><tr><th style="text-align:left;">Field Name</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Opening Amount</strong></td><td style="text-align:left;">The cash amount placed in the drawer at the beginning of the POS session.</td></tr><tr><td style="text-align:left;"><strong>Expected Amount in Drawer</strong></td><td style="text-align:left;">The system-calculated cash balance based on sales, refunds, and transactions performed during the day.</td></tr><tr><td style="text-align:left;"><strong>Difference</strong></td><td style="text-align:left;">The variance between the expected drawer amount and the actual counted cash.</td></tr><tr><td style="text-align:left;"><strong>Payment Mode</strong></td><td style="text-align:left;">The method through which the customer made the payment, such as cash or card.</td></tr><tr><td style="text-align:left;"><strong>Paid</strong></td><td style="text-align:left;">The total amount received from customers using the selected payment mode.</td></tr><tr><td style="text-align:left;"><strong>Change</strong></td><td style="text-align:left;">The amount returned to customers as balance after payment.</td></tr><tr><td style="text-align:left;"><strong>Refund</strong></td><td style="text-align:left;">The total amount refunded to customers during the session.</td></tr><tr><td style="text-align:left;"><strong>Total</strong></td><td style="text-align:left;">The net amount remaining after accounting for paid, change, and refund values.</td></tr><tr><td style="text-align:left;"><strong>Grand Total</strong></td><td style="text-align:left;">The final combined total of all payment modes recorded in the drawer.</td></tr><tr><td style="text-align:left;"><strong>Remarks</strong></td><td style="text-align:left;">Optional notes added by the cashier to explain discrepancies or record important observations.</td></tr></tbody></table><hr><h2 id="today-transaction" tabindex="-1"><a class="header-anchor" href="#today-transaction"><span>Today Transaction</span></a></h2><p>Under the <strong>Cashier</strong> menu, the <strong>Today Transaction</strong> option provides real-time cash insights.</p><p><img src="/pos-for-woocommerce/images/woocommerce-pos/todaystransactions.webp" alt="ManageoutletAndPosUser"></p><h3 id="real-time-insights-ledger-fields" tabindex="-1"><a class="header-anchor" href="#real-time-insights-ledger-fields"><span>Real-Time Insights &amp; Ledger Fields</span></a></h3><table><thead><tr><th style="text-align:left;">Parameter / Field</th><th style="text-align:left;">Explanation</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Cash</strong></td><td style="text-align:left;">Displays the total cash amount currently available in the drawer for the active session.</td></tr><tr><td style="text-align:left;"><strong>Today’s Transactions</strong></td><td style="text-align:left;">Shows all cash-related activities performed during the current drawer session.</td></tr><tr><td style="text-align:left;"><strong>Current Opening Drawer ID</strong></td><td style="text-align:left;">Identifies the active drawer session against which all transactions are recorded.</td></tr><tr><td style="text-align:left;"><strong>Drawer Transaction ID</strong></td><td style="text-align:left;">A unique identifier assigned to each individual drawer transaction.</td></tr><tr><td style="text-align:left;"><strong>Opening Drawer ID</strong></td><td style="text-align:left;">Links the transaction to the specific drawer opening session.</td></tr><tr><td style="text-align:left;"><strong>Transaction Type</strong></td><td style="text-align:left;">Indicates whether the transaction is a credit (cash added) or debit (cash removed).</td></tr><tr><td style="text-align:left;"><strong>Transaction ID</strong></td><td style="text-align:left;">References the source of the transaction, such as a manual entry or an order ID.</td></tr><tr><td style="text-align:left;"><strong>Transaction For</strong></td><td style="text-align:left;">Specifies whether the transaction is related to an order or a manual adjustment.</td></tr><tr><td style="text-align:left;"><strong>Payment Method</strong></td><td style="text-align:left;">Shows the mode of payment used, such as cash.</td></tr><tr><td style="text-align:left;"><strong>Amount</strong></td><td style="text-align:left;">Displays the transaction value, with plus or minus signs indicating addition or deduction.</td></tr></tbody></table><h3 id="creating-a-manual-transaction" tabindex="-1"><a class="header-anchor" href="#creating-a-manual-transaction"><span>Creating a Manual Transaction</span></a></h3><p>To create a new transaction, click on <strong>Create Transaction</strong> and submit the required details.</p><p><img src="/pos-for-woocommerce/images/woocommerce-pos/createtransaction.webp" alt="ManageoutletAndPosUser"></p><table><thead><tr><th style="text-align:left;">Form Field</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Transaction Type</strong></td><td style="text-align:left;">Specifies whether the transaction is a <strong>credit</strong> (cash added) or <strong>debit</strong> (cash removed) from the drawer.</td></tr><tr><td style="text-align:left;"><strong>Transaction Amount</strong></td><td style="text-align:left;">The exact monetary value of the transaction being recorded.</td></tr><tr><td style="text-align:left;"><strong>Transaction Payment</strong></td><td style="text-align:left;">The payment method used for the transaction, such as <strong>cash</strong> or <strong>card</strong>.</td></tr><tr><td style="text-align:left;"><strong>Transaction Note</strong></td><td style="text-align:left;">A brief description or remark explaining the purpose of the transaction.</td></tr></tbody></table><hr><h2 id="sale-history" tabindex="-1"><a class="header-anchor" href="#sale-history"><span>Sale History</span></a></h2><p>WooCommerce POS provides a detailed <strong>Sale History</strong> section for tracking completed transactions.</p><p><img src="/pos-for-woocommerce/images/woocommerce-pos/completetransactions.webp" alt="Opening Cash Amount"></p><table><thead><tr><th style="text-align:left;">Field Name</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Opening Amount</strong></td><td style="text-align:left;">The initial cash present in the drawer at the start of the POS session.</td></tr><tr><td style="text-align:left;"><strong>Payments</strong></td><td style="text-align:left;">The total amount received through all payment methods during the session.</td></tr><tr><td style="text-align:left;"><strong>Closing Amount</strong></td><td style="text-align:left;">The final cash balance in the drawer at the end of the POS session.</td></tr><tr><td style="text-align:left;"><strong>Opened At</strong></td><td style="text-align:left;">The date and time when the cash drawer was initially opened.</td></tr><tr><td style="text-align:left;"><strong>Closed At</strong></td><td style="text-align:left;">The date and time when the cash drawer was closed at the end of the session.</td></tr><tr><td style="text-align:left;"><strong>Opening Note</strong></td><td style="text-align:left;">Optional remarks or notes entered at the time of opening the drawer.</td></tr><tr><td style="text-align:left;"><strong>Closing Note</strong></td><td style="text-align:left;">Optional remarks or notes added when closing the drawer to explain discrepancies or observations.</td></tr></tbody></table><hr>',39)])])}]])}}]);